"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { 
  Zap, Loader2, Navigation, ShieldAlert, Timer, Flag, Trophy, Activity, MapPin, Crown, Star, Gauge, History, ArrowUpRight, StopCircle, Play, Target, Clock, Map as MapIcon, XCircle
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking, useCollection } from "@/firebase";
import { doc, collection, query, where, getCountFromServer, orderBy, limit } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";

const RouteMap = dynamic(() => import("../../components/telemetry/route-map"), { 
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 rounded-3xl">
      <Loader2 className="w-6 h-6 animate-spin text-red-500" />
    </div>
  )
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const { 
    speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps, 
    currentCoords, heading, routePoints, telemetry, startTime,
    runMode, dragTime, isDragFinished, isWakeLockActive,
    isNavigating, destination, routeData,
    setRunMode, startTrip, stopTrip, resetTrip, clearNavigation, requestWakeLock 
  } = useDriving();
  
  const [mounted, setMounted] = useState(false);
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [kosovoRank, setKosovoRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  
  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  const threeHoursAgo = useMemo(() => {
    const d = new Date();
    d.setHours(d.getHours() - 3);
    return d.toISOString();
  }, []);

  const reportsQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(
      collection(db, "radar_reports"), 
      where("createdAt", ">=", threeHoursAgo),
      orderBy("createdAt", "desc"), 
      limit(50)
    );
  }, [db, threeHoursAgo]);
  
  const { data: reports } = useCollection(reportsQuery);

  const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371000;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  };

  const activeAlert = useMemo(() => {
    if (!reports || !currentCoords) return null;
    return reports.find(r => {
      const dist = calculateDistance(currentCoords.lat, currentCoords.lng, r.lat, r.lng);
      return dist < 2500; // 2.5km rreze për alerte
    });
  }, [reports, currentCoords]);

  useEffect(() => {
    setMounted(true);
  }, []);

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    
    try {
      const publicRunsCol = collection(db, "public_runs");
      let kosovoQuery;
      let cityQuery;

      if (runMode === 'free') {
        const val = peakSpeed;
        if (val <= 0) {
          setIsRankingLoading(false);
          return;
        }
        kosovoQuery = query(publicRunsCol, where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        }
      } else {
        const modeName = runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile';
        const val = dragTime;
        if (!val) {
          setIsRankingLoading(false);
          return;
        }
        kosovoQuery = query(publicRunsCol, where("runType", "==", modeName), where("dragTime", "<", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", modeName), where("dragTime", "<", val));
        }
      }

      const kosovoSnapshot = await getCountFromServer(kosovoQuery);
      setKosovoRank(kosovoSnapshot.data().count + 1);

      if (cityQuery) {
        const citySnapshot = await getCountFromServer(cityQuery);
        setCityRank(citySnapshot.data().count + 1);
      }
    } catch (e) {
      console.error("Dështoi llogaritja e ranking:", e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
      toast({ title: "MISIONI U KRYE", description: `Koha jote: ${dragTime?.toFixed(2)}s` });
    }
  }, [isDragFinished, dragTime, mounted, showSummary]);

  const handleStartMission = () => {
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    stopTrip();
    setShowSummary(true);
    calculateRanks();
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const rpm = useMemo(() => {
    if (speed === 0) return 800;
    const gear = Math.floor(speed / 60) + 1;
    const speedInGear = speed % 60;
    const baseRpm = 1200 + (gear * 100);
    const calculated = baseRpm + (speedInGear * 110);
    return Math.min(Math.floor(calculated), 8000);
  }, [speed]);

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "GABIM", description: "Lejoni GPS-in për të raportuar." });
      return;
    }
    setIsReporting(type);
    
    let locationName = profile?.city || "Kosovë";
    try {
      const response = await fetch(`https://photon.komoot.io/reverse?lon=${currentCoords.lng}&lat=${currentCoords.lat}`);
      const data = await response.json();
      if (data.features && data.features.length > 0) {
        const p = data.features[0].properties;
        locationName = p.name || p.street || p.city || locationName;
      }
    } catch (e) { console.warn("Geocoding dështoi"); }

    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: locationName,
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    
    setTimeout(() => {
      setIsReporting(null);
      toast({ title: "RAPORTUAR", description: `${type} u shënua në: ${locationName}` });
    }, 400);
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Prishtinë",
      runType: runMode === 'free' ? 'Top Speed' : runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile',
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      telemetry: telemetry,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };
    
    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);
    
    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);
    
    toast({ title: "U RUAJT", description: "Të dhënat u sinkronizuan në Ranking." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
    setCityRank(null);
    setKosovoRank(null);
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-background flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  return (
    <div className="flex flex-col min-h-full bg-background text-foreground pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      <div className="absolute inset-0 bg-gradient-to-b from-red-600/10 via-transparent to-transparent pointer-events-none" />
      
      <div className="p-4 space-y-4 z-20 shrink-0">
        {!hasGps && (
          <Alert variant="destructive" className="rounded-2xl bg-red-950/40 border-red-500/50 backdrop-blur-xl">
            <ShieldAlert className="h-5 w-5 text-red-500" />
            <AlertTitle className="text-[10px] font-black uppercase tracking-widest text-red-500">KËRKOHET LOKACIONI</AlertTitle>
            <AlertDescription className="text-[11px] font-medium uppercase leading-relaxed text-red-100">
              Lejoni qasjen në GPS për të matur performancën.
            </AlertDescription>
          </Alert>
        )}

        <div className="flex items-center justify-between px-2">
           <div className="flex items-center gap-2">
             <div className={cn("w-2.5 h-2.5 rounded-full", isWakeLockActive ? "bg-red-500 shadow-[0_0_10px_#ef4444]" : "bg-zinc-700")} />
             <span className="text-[10px] font-black uppercase text-muted-foreground tracking-[0.2em]">
               {isWakeLockActive ? "HUD AKTIV" : "HUD GATI"}
             </span>
           </div>
           <Badge variant="outline" className="text-[9px] font-black uppercase border-white/10 text-muted-foreground bg-white/5 py-1 tracking-widest">
             {hasGps ? "LIDHJA TELEMETRIKE" : "KËRKOHET GPS"}
           </Badge>
        </div>

        <div className="grid grid-cols-3 gap-4 w-full">
          <Button onClick={() => handleQuickReport('Radar')} disabled={!!isReporting} className="h-20 flex flex-col gap-2 rounded-2xl glass-card bg-red-600/10 border-red-500/30 text-white active:scale-95 transition-all">
            {isReporting === 'Radar' ? <Loader2 className="w-5 h-5 animate-spin text-red-500" /> : <span className="text-2xl">🚨</span>}
            <span className="text-[10px] font-black uppercase tracking-widest text-red-500">RADAR</span>
          </Button>
          <Button onClick={() => handleQuickReport('Polici')} disabled={!!isReporting} className="h-20 flex flex-col gap-2 rounded-2xl glass-card bg-blue-600/10 border-blue-500/30 text-white active:scale-95 transition-all">
            {isReporting === 'Polici' ? <Loader2 className="w-5 h-5 animate-spin text-blue-500" /> : <span className="text-2xl">🚔</span>}
            <span className="text-[10px] font-black uppercase tracking-widest text-blue-400">POLICI</span>
          </Button>
          <Button onClick={() => handleQuickReport('Kontrollë')} disabled={!!isReporting} className="h-20 flex flex-col gap-2 rounded-2xl glass-card bg-zinc-800/30 border-white/10 text-white active:scale-95 transition-all">
            {isReporting === 'Kontrollë' ? <Loader2 className="w-5 h-5 animate-spin text-zinc-400" /> : <span className="text-2xl">🚗</span>}
            <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400">PONT</span>
          </Button>
        </div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center relative px-4 py-2 overflow-visible">
        <div className="w-full max-w-[340px] mb-8 z-20">
          {isNavigating ? (
            <Card className="glass-card p-5 rounded-3xl border-accent/20 bg-zinc-950/40 backdrop-blur-xl">
               <div className="flex items-center gap-5">
                  <div className="w-14 h-14 bg-accent/10 rounded-2xl flex items-center justify-center border border-accent/20">
                    <MapIcon className="w-7 h-7 text-accent" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <span className="text-[10px] font-black text-accent uppercase tracking-widest leading-none block mb-1">DREJT DESTINACIONIT</span>
                    <h3 className="text-sm font-black text-white uppercase truncate">{destination?.name}</h3>
                  </div>
                  <div className="flex flex-col items-end shrink-0">
                     <span className="text-2xl font-black text-white leading-none">{Math.round((routeData?.duration || 0) / 60)}</span>
                     <span className="text-[9px] font-black text-accent uppercase tracking-widest">MIN</span>
                  </div>
               </div>
            </Card>
          ) : (
            <div className="grid grid-cols-4 gap-2 w-full">
              {[
                { id: 'free', label: 'LIRË', icon: Navigation },
                { id: '0-100', label: '0-100', icon: Zap },
                { id: '100-200', label: '100-200', icon: Timer },
                { id: '1/4mile', label: '1/4 M', icon: Flag }
              ].map((mode) => (
                <Button 
                  key={mode.id}
                  onClick={() => !isDriving && setRunMode(mode.id as RunMode)}
                  className={cn(
                    "h-14 flex flex-col gap-1 rounded-2xl border transition-all text-[9px] font-black uppercase z-10",
                    runMode === mode.id 
                      ? `bg-red-600 text-white border-red-600 shadow-xl` 
                      : "bg-white/5 border-white/10 text-muted-foreground hover:bg-white/10",
                    isDriving && "opacity-50 cursor-not-allowed"
                  )}
                >
                  <mode.icon className="w-4 h-4" />
                  {mode.label}
                </Button>
              ))}
            </div>
          )}
        </div>

        <div className="relative w-full aspect-square flex items-center justify-center max-w-[340px] mx-auto overflow-visible mb-8">
          <div className="w-full h-full relative flex items-center justify-center">
            <svg viewBox="0 0 400 400" className="w-full h-full transform -rotate-90 overflow-visible absolute inset-0">
              <circle cx="200" cy="200" r="180" stroke="currentColor" strokeWidth="2" fill="transparent" className="text-white/[0.05]" />
              <circle
                cx="200" cy="200" r="180"
                stroke="currentColor" strokeWidth="14" strokeLinecap="butt"
                fill="transparent"
                strokeDasharray={2 * Math.PI * 180}
                style={{ 
                  strokeDashoffset: (2 * Math.PI * 180) - (rpm / 8000) * (2 * Math.PI * 180),
                  transition: 'stroke-dashoffset 0.15s cubic-bezier(0.4, 0, 0.2, 1)'
                }}
                className={cn(
                  "transition-all",
                  isNavigating ? "text-accent drop-shadow-[0_0_20px_rgba(77,224,244,0.4)]" : (
                    rpm > 7000 ? "text-red-600 drop-shadow-[0_0_30px_rgba(220,38,38,1)]" : 
                    rpm > 6000 ? "text-red-500" : 
                    "text-primary"
                  )
                )}
              />
            </svg>
            
            <div className="z-20 flex flex-col items-center w-[85%] h-[85%] rounded-full relative overflow-hidden">
              {isNavigating ? (
                <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950/10 backdrop-blur-[1px]">
                   <div className="absolute inset-0 z-0 scale-125 pointer-events-none">
                     <RouteMap 
                        points={routeData?.coordinates || []} 
                        userLocation={currentCoords}
                        heading={heading}
                     />
                   </div>
                   
                   <div className="absolute top-8 right-10 z-20 pointer-events-none flex flex-col items-end">
                      <span className="text-3xl font-black text-white leading-none drop-shadow-[0_0_15px_rgba(255,255,255,0.4)] tabular-nums">
                        {speed}
                      </span>
                      <span className="text-[10px] font-black text-accent uppercase tracking-widest">KM/H</span>
                   </div>

                   <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-20 w-full px-10">
                      <div className="bg-black/70 backdrop-blur-md py-2.5 rounded-full border border-white/10 shadow-2xl flex items-center justify-center gap-3">
                        <Navigation className="w-3.5 h-3.5 text-accent" />
                        <span className="text-[10px] font-black text-white uppercase tracking-widest leading-none truncate max-w-[120px]">
                          {destination?.name.split(',')[0]}
                        </span>
                      </div>
                   </div>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full">
                  <div className="flex items-center gap-2 mb-3">
                     <Activity className={cn("w-4 h-4", rpm > 6500 ? "text-red-500" : "text-primary")} />
                     <span className="text-[10px] font-black uppercase tracking-[0.3em] text-muted-foreground">TELEMETRIA LIVE</span>
                  </div>
                  <span className={cn(
                    "font-black tracking-tighter leading-none transition-all duration-150 tabular-nums text-white",
                    speed > 99 ? "text-[8.5rem]" : "text-[10.5rem]",
                    speed > 100 && "text-red-500"
                  )}>
                    {speed}
                  </span>
                  <div className="flex flex-col items-center -mt-6">
                    <span className={cn("text-[16px] font-black uppercase tracking-[0.6em] opacity-90", speed > 100 ? "text-red-500" : "text-primary")}>KM / H</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="w-full max-w-[320px] z-20 space-y-6">
          {isNavigating ? (
            <Card className="glass-card p-6 rounded-[2.5rem] border-white/10 bg-zinc-950/60 shadow-2xl">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <ArrowUpRight className="w-5 h-5 text-accent" />
                  <span className="text-[12px] font-black text-white uppercase tracking-widest">UDHËTIMI AKTIV</span>
                </div>
                <Badge variant="outline" className="text-[9px] font-black text-accent border-accent/20">GPS LIVE</Badge>
              </div>
              
              <div className="grid grid-cols-2 gap-6">
                 <div className="flex flex-col">
                    <span className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">DREJT</span>
                    <span className="text-sm font-black text-white uppercase truncate">{destination?.name.split(',')[0]}</span>
                 </div>
                 <div className="flex flex-col items-end">
                    <span className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">DISTANCA</span>
                    <span className="text-sm font-black text-accent uppercase">{((routeData?.distance || 0) / 1000).toFixed(1)} KM</span>
                 </div>
              </div>

              <div className="mt-5 pt-4 border-t border-white/5 flex items-center justify-between">
                 <div className="flex items-center gap-3">
                    <Clock className="w-5 h-5 text-accent" />
                    <span className="text-2xl font-black text-white leading-none">
                      {Math.round((routeData?.duration || 0) / 60)} <span className="text-xs text-muted-foreground font-medium uppercase ml-1">MIN</span>
                    </span>
                 </div>
                 <Button 
                    onClick={clearNavigation} 
                    variant="ghost" 
                    className="h-10 rounded-2xl px-5 bg-red-600/10 text-red-500 border border-red-500/20 hover:bg-red-600/20 text-[10px] font-black uppercase"
                  >
                    STOP NAV
                  </Button>
              </div>
            </Card>
          ) : (
            <Button 
              onClick={() => isDriving ? handleStopMission() : handleStartMission()} 
              className={cn(
                "w-full h-16 rounded-[2rem] font-black text-xl uppercase tracking-tighter transition-all shadow-2xl active:scale-95 border-b-4", 
                "bg-red-600 hover:bg-red-700 text-white border-red-900"
              )}
            >
              {isDriving ? <span>STOP</span> : <span>START TRIP</span>}
            </Button>
          )}
          
          <div className="grid grid-cols-2 gap-4">
            <Card className="glass-card p-5 flex flex-col items-center rounded-3xl sporty-gradient">
              <span className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">DISTANCA</span>
              <span className="text-base font-black text-white">{(tripDistance / 1000).toFixed(2)} KM</span>
            </Card>
            <Card className="glass-card p-5 flex flex-col items-center rounded-3xl sporty-gradient">
              <span className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mb-1">PEAK SPEED</span>
              <span className="text-base font-black text-red-500">{peakSpeed} KM/H</span>
            </Card>
          </div>
        </div>
      </div>

      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="glass border-white/10 w-[94%] sm:max-w-md max-h-[90vh] overflow-y-auto no-scrollbar rounded-[3rem] p-0 shadow-2xl">
          <div className="p-10 space-y-8 sporty-gradient">
            <DialogHeader className="flex flex-col items-center gap-3">
              <div className="w-16 h-16 bg-red-600/15 rounded-3xl flex items-center justify-center border border-red-500/20 shadow-xl">
                <Trophy className="w-8 h-8 text-red-500" />
              </div>
              <DialogTitle className="text-xl font-black uppercase tracking-tighter text-center">REZULTATET E GARËS</DialogTitle>
            </DialogHeader>
            
            <div className="space-y-8">
              <div className="space-y-4">
                <div className="flex items-center justify-between px-1">
                  <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-red-500">TELEMETRIA E RUAJTUR</h3>
                  <Badge variant="outline" className="text-[9px] font-black text-accent border-accent/20">PRO MODE</Badge>
                </div>
                <Card className="glass-card border-white/10 p-6 rounded-[2.5rem] space-y-5 bg-zinc-950/50">
                  <div className="h-48 w-full rounded-[2rem] border border-white/5 overflow-hidden relative shadow-inner">
                    <RouteMap points={routePoints} />
                  </div>
                  
                  <div className="grid grid-cols-3 gap-3">
                    <div className="bg-white/5 p-4 flex flex-col items-center rounded-2xl">
                      <Timer className="w-4 h-4 text-muted-foreground mb-2" />
                      <span className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">KOHA</span>
                      <span className="text-sm font-black text-white mt-1">{formatTime(tripTime)}</span>
                    </div>
                    <div className="bg-white/5 p-4 flex flex-col items-center rounded-2xl">
                      <MapPin className="w-4 h-4 text-accent mb-2" />
                      <span className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">DISTANCA</span>
                      <span className="text-sm font-black text-accent mt-1">{(tripDistance / 1000).toFixed(2)} KM</span>
                    </div>
                    <div className="bg-white/5 p-4 flex flex-col items-center rounded-2xl">
                      <Trophy className="w-4 h-4 text-red-500 mb-2" />
                      <span className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">MAX</span>
                      <span className="text-sm font-black text-red-500 mt-1">{peakSpeed} KM/H</span>
                    </div>
                  </div>
                </Card>
              </div>

              <div className="space-y-4">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-accent px-1">RANKIMI AKTUAL</h3>
                <Card className="glass-card border-accent/30 bg-accent/5 p-6 rounded-[2.5rem] relative overflow-hidden">
                   {isRankingLoading ? (
                     <div className="flex flex-col items-center py-6 gap-3">
                       <Loader2 className="w-8 h-8 animate-spin text-accent" />
                       <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">DUKE LLOGARITUR RANKING...</span>
                     </div>
                   ) : (
                     <div className="space-y-5">
                        <div className="flex items-center gap-5">
                           <div className="w-12 h-12 rounded-2xl bg-accent flex items-center justify-center shadow-lg">
                             <Star className="w-6 h-6 text-background fill-background" />
                           </div>
                           <div className="flex flex-col">
                             <span className="text-[10px] font-black text-accent uppercase tracking-widest">POZICIONI NË KOSOVË</span>
                             <span className="text-lg font-black text-white uppercase italic">#{kosovoRank || '--'} NË KOSOVË 🔥</span>
                           </div>
                        </div>
                        <div className="grid grid-cols-1 gap-3">
                           <div className="flex items-center justify-between bg-white/5 p-4 rounded-2xl border border-white/5">
                             <div className="flex items-center gap-3">
                               <MapPin className="w-4 h-4 text-accent" />
                               <span className="text-[10px] font-black uppercase text-muted-foreground">{profile?.city || "QYTETI"}</span>
                             </div>
                             <span className="text-base font-black text-white">#{cityRank || '--'}</span>
                           </div>
                        </div>
                     </div>
                   )}
                </Card>
              </div>
            </div>

            <div className="flex flex-col gap-3 pt-4">
              <Button onClick={handleSaveRun} disabled={isSaving || isRankingLoading} className="w-full h-16 bg-red-600 hover:bg-red-700 text-white rounded-[1.8rem] font-black uppercase text-base shadow-2xl active:scale-95 border-b-4 border-red-900">RUAJ TË DHËNAT</Button>
              <Button variant="ghost" className="w-full h-12 rounded-2xl font-black uppercase text-[10px] text-zinc-500 hover:text-white" onClick={() => { setShowSummary(false); resetTrip(); setCityRank(null); setKosovoRank(null); }}>ANULO DHE FSHIJ</Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}